public class Main {

    static int square(int x) {
        return x * x;
    }

    static int add(int a, int b) {
        return a + b;
    }

    static String greet(String name) {
        return "Merhaba, " + name + "!";
    }

    static String greet(String name, String greeting) {
        return greeting + ", " + name + "!";
    }

    static double multiply(double a, double b) {
        return a * b;
    }

    static int multiply(int a, int b) {
        return a * b;
    }

    public static void main(String[] args) {
        System.out.println("Kare: " + square(5));
        System.out.println("Toplam: " + add(3, 7));
        System.out.println(greet("Ayse"));
        System.out.println(greet("Mehmet", "Selam"));
        System.out.println("Tam carpim: " + multiply(4, 5));
        System.out.println("Ondalik carpim: " + multiply(2.5, 3.0));
    }
}
